class MyApp extends StatelessWidget {
  final AuthManager _authManager = AuthManager();

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: FutureBuilder<bool>(
        future: _authManager.isLoggedIn(),
        builder: (context, snapshot) {
